    /// <summary>
    /// Get all variables as a list (standardized Dict property)
    /// </summary>
    public static IReadOnlyList<Variable> Fixture => _variablesDict.Values.ToList();

    /// <summary>
    /// Get variable by ID with O(1) lookup
    /// </summary>
    public static Variable? GetVariable(int variableId) =>
        _variablesDict.TryGetValue(variableId, out var variable) ? variable : null;

    /// <summary>
    /// Get all variables as immutable dictionary for O(1) operations
    /// </summary>
    public static IImmutableDictionary<int, Variable> Variables => _variablesDict;

    /// <summary>
    /// Check if variable exists by ID
    /// </summary>
    public static bool Contains(int variableId) => _variablesDict.ContainsKey(variableId);

    /// <summary>
    /// Get total count of variables
    /// </summary>
    public static int Count => _variablesDict.Count;

    /// <summary>
    /// Get variables by address pattern (for PLC addressing)
    /// </summary>
    public static IEnumerable<Variable> GetByAddressPattern(string pattern) =>
        _variablesDict.Values.Where(v => v.Address.Contains(pattern));

    /// <summary>
    /// Get variables by NetType (for type-specific operations)
    /// </summary>
    public static IEnumerable<Variable> GetByNetType(string netType) =>
        _variablesDict.Values.Where(v => v.NetType == netType);

    /// <summary>
    /// Get DB block variables (most common addressing scheme)
    /// </summary>
    public static IEnumerable<Variable> GetDbVariables() =>
        _variablesDict.Values.Where(v => v.Address.StartsWith("DB"));

    /// <summary>
    /// Get Temperature and TemperingTime variables (common test scenario)
    /// </summary>
    public static (Variable? Temperature, Variable? TemperingTime) GetTemperatureVariables() =>
        (GetVariable(45), GetVariable(46));
